import math

def dpo_loss(log_probs_chosen_policy: list, log_probs_rejected_policy: list,
            log_probs_chosen_ref: list, log_probs_rejected_ref: list,
            beta: float) -> dict:
    def sigmoid(x):
        return 1.0 / (1.0 + math.exp(-x))

    chosen_rewards = [
        beta * (lp - lr)
        for lp, lr in zip(log_probs_chosen_policy, log_probs_chosen_ref)
    ]
    rejected_rewards = [
        beta * (lp - lr)
        for lp, lr in zip(log_probs_rejected_policy, log_probs_rejected_ref)
    ]

    losses = [
        -math.log(sigmoid(cw - rw))
        for cw, rw in zip(chosen_rewards, rejected_rewards)
    ]

    avg_loss = sum(losses) / len(losses)

    return {
        'loss': round(avg_loss, 4),
        'chosen_rewards': [round(r, 4) for r in chosen_rewards],
        'rejected_rewards': [round(r, 4) for r in rejected_rewards],
    }
